import { describe, it } from "vitest";
import assert from "node:assert/strict";
import { ProjectSandbox } from "../../src/server/agent/project-sandbox.js";
import type { Component } from "../../src/server/agent/project-config-store.js";

type ExecCall = {
	containerId: string;
	args: string[];
	opts?: { cwd?: string; env?: Record<string, string>; timeout?: number };
};

function makeSandboxRecorder(): { sandbox: ProjectSandbox; calls: ExecCall[] } {
	const sandbox = new ProjectSandbox({
		projectId: "sandbox-local-only-test",
		projectDir: "/host/project",
		repoUrl: "https://example.invalid/repo.git",
		image: "bobbit-test-image",
	});
	const calls: ExecCall[] = [];
	(sandbox as any).containerId = "container-local-only";
	(sandbox as any)._dockerExec = async (
		containerId: string,
		args: string[],
		opts?: { cwd?: string; env?: Record<string, string>; timeout?: number },
	): Promise<string> => {
		calls.push({ containerId, args: [...args], opts });
		return "";
	};
	return { sandbox, calls };
}

function assertNoSandboxAutoPublish(calls: ExecCall[]): void {
	const rendered = calls.map(call => `${call.opts?.cwd ?? ""} $ ${call.args.join(" ")}`);
	const pushCommands = rendered.filter(command => /\bgit\s+push\b/.test(command));
	const hookCommands = rendered.filter(command => command.includes("post-commit") || command.includes("git rev-parse --git-dir"));
	assert.deepEqual(pushCommands, [], "sandbox worktree creation must not publish with git push");
	assert.deepEqual(hookCommands, [], "sandbox worktree creation must not install a post-commit hook");
}

describe("ProjectSandbox local-only worktrees", () => {
	it("createWorktree does not install a post-commit hook or publish the branch", async () => {
		const { sandbox, calls } = makeSandboxRecorder();

		const worktreePath = await sandbox.createWorktree("session/local-only", "session/local-only", "HEAD");

		assert.equal(worktreePath, "/workspace-wt/session/local-only");
		assert.ok(
			calls.some(call => call.args.join(" ") === "git worktree add /workspace-wt/session/local-only -b session/local-only HEAD"),
			"expected createWorktree to create the container worktree",
		);
		assertNoSandboxAutoPublish(calls);
	});

	it("createWorktreeSet does not install post-commit hooks or publish repo worktree branches", async () => {
		const { sandbox, calls } = makeSandboxRecorder();
		const components: Component[] = [
			{ name: "api", repo: "services/api" },
			{ name: "web", repo: "apps/web" },
		];

		const result = await sandbox.createWorktreeSet("team/local-only", "team/local-only", components, "HEAD");

		assert.equal(result.container, "/workspace-wt/team/local-only");
		assert.deepEqual(result.worktrees, [
			{ repo: "services/api", worktreePath: "/workspace-wt/team/local-only/services/api" },
			{ repo: "apps/web", worktreePath: "/workspace-wt/team/local-only/apps/web" },
		]);
		assert.ok(
			calls.some(call => call.args.join(" ") === "git worktree add /workspace-wt/team/local-only/services/api -b team/local-only HEAD"),
			"expected createWorktreeSet to create the first repo worktree",
		);
		assert.ok(
			calls.some(call => call.args.join(" ") === "git worktree add /workspace-wt/team/local-only/apps/web -b team/local-only HEAD"),
			"expected createWorktreeSet to create the second repo worktree",
		);
		assertNoSandboxAutoPublish(calls);
	});
});
